package com.arkeomag.pro; import android.content.*;import android.view.*;import android.graphics.*;import java.util.*;
public class RadarView extends View{Paint p=new Paint(1);float angle=0,signal=0;ArrayList<float[]> blips=new ArrayList<>(); public RadarView(Context c){super(c);} public void update(float v){signal=v;if(v>10&&Math.random()>.82)blips.add(new float[]{(float)Math.random(),(float)Math.random(),1}); if(blips.size()>40)blips.remove(0);invalidate();} protected void onDraw(Canvas c){int w=getWidth(),h=getHeight(),r=Math.min(w,h)/2-25,cx=w/2,cy=h/2;p.setColor(Color.rgb(4,15,20));c.drawRect(0,0,w,h,p);p.setStyle(Paint.Style.STROKE);p.setStrokeWidth(2);p.setColor(Color.argb(120,0,255,180));for(int i=1;i<=4;i++)c.drawCircle(cx,cy,r*i/4,p);c.drawLine(cx-r,cy,cx+r,cy,p);c.drawLine(cx,cy-r,cx,cy+r,p);p.setStyle(Paint.Style.FILL);for(float[] b:blips){float rr=b[0]*r,aa=b[1]*6.28318f;p.setColor(Color.argb(180,255,230,0));c.drawCircle(cx+(float)Math.cos(aa)*rr,cy+(float)Math.sin(aa)*rr,7+signal/8,p);}p.setStrokeWidth(8);p.setColor(Color.rgb(0,255,190));float a=(float)Math.toRadians(angle);c.drawLine(cx,cy,cx+(float)Math.cos(a)*r,cy+(float)Math.sin(a)*r,p);angle=(angle+3)%360;postInvalidateDelayed(33);p.setStyle(Paint.Style.FILL);}}
